html:
{% set cards_per_row = 2 %}
{% set rows = 5 %}

<style>
  body { margin: 0; padding: 0; }
  .sheet {
    width: 210mm;
    padding: 8mm;
    box-sizing: border-box;
  }
  .row {
    display: flex;
    flex-direction: row;
    gap: 4mm;
    margin-bottom: 4mm;
  }
  .card {
    flex: 1;
    border: 1px solid #333;
    border-radius: 4mm;
    padding: 4mm;
    text-align: center;
    font-family: Arial, sans-serif;
    background: #fff;
    page-break-inside: avoid;
  }
  .card img {
    width: 38mm;
    height: 38mm;
    display: block;
    margin: 2mm auto;
  }
  .card .code {
    font-size: 8pt;
    font-weight: bold;
    letter-spacing: 1px;
    margin-top: 2mm;
  }
  .card .points {
    font-size: 11pt;
    font-weight: bold;
    color: #1a1a1a;
    margin-top: 1mm;
  }
  .card .expiry {
    font-size: 7pt;
    color: #666;
    margin-top: 1mm;
  }
  .card .brand {
    font-size: 7pt;
    color: #999;
    margin-top: 2mm;
    text-transform: uppercase;
    letter-spacing: 2px;
  }
</style>

<div class="sheet">
  {% for row in range(rows) %}
  <div class="row">
    {% for col in range(cards_per_row) %}
    <div class="card">
      <div class="brand">Scan &amp; Earn</div>
      <img src="{{ get_coupon_qr(doc.code) }}" alt="{{ doc.code }}">
      <div class="code">{{ doc.code }}</div>
      <div class="points">{{ doc.points_value | int }} Points</div>
      <div class="expiry">Valid till {{ frappe.format(doc.expiry_date, {'fieldtype': 'Date'}) }}</div>
    </div>
    {% endfor %}
  </div>
  {% endfor %}
</div>
